// Extra celebrity profiles — A–Z directory expansion (~500 slim profiles)

type ExtraCat = 'Athletes'|'Actors'|'Musicians'|'Entrepreneurs'|'Politicians'|'Models'
type ExtraAssetType = 'jet'|'yacht'|'real_estate'|'car'|'watch'|'art'|'helicopter'|'island'|'sports_team'|'rocket'

interface ExtraAsset {
  id: string; type: ExtraAssetType; name: string; description: string
  estimatedValue: number; image: string; likes: number; isNew?: boolean
  year?: number; location?: string; specs?: string
}
export interface ExtraCelebrity {
  id: string; name: string; category: ExtraCat; netWorth: number
  avatar: string; coverImage: string; nationality: string; bio: string
  assets: ExtraAsset[]; trending: boolean; birthdate: string; birthplace: string
  gender: 'Male'|'Female'; height: string; profession: string; photos: string[]
  relationships?: { parents?: string[]; spouse?: string; partner?: string; siblings?: string[]; children?: string[] }
  gossip?: { title: string; summary: string }[]
}

