const av = (n: string) => `https://ui-avatars.com/api/?name=${encodeURIComponent(n)}&background=1a1a1a&color=c9a84c&size=200&bold=true`

function mk(
  id: string, name: string, cat: ExtraCat, nw: number, nat: string, prof: string,
  bd: string, bp: string, g: 'Male'|'Female', ht: string, bio: string, avatar: string,
  a1t: ExtraAssetType, a1n: string, a1v: number, a1d: string, trend = false
): ExtraCelebrity {
  return {
    id, name, category: cat, netWorth: nw, nationality: nat, profession: prof,
    birthdate: bd, birthplace: bp, gender: g, height: ht, bio,
    avatar: avatar || av(name), coverImage: CI[cat], trending: trend, photos: [avatar || av(name)],
    assets: [{ id: `${id}-1`, type: a1t, name: a1n, description: a1d, estimatedValue: a1v, image: AI[a1t], likes: Math.round(a1v * 60 + 800) }],
  }
}

